copywith_sentinel.code:
// Сентинель — top-level константа в aq_element.dart
const _absent = Object();

// В copyWith:
ColumnElement copyWith({
  Object? borderColor = _absent,  // nullable через Object?
  String? id,                     // non-nullable — обычно
}) {
  return ColumnElement(
    id: id ?? this.id,
    borderColor: identical(borderColor, _absent)
        ? this.borderColor          // не передавали → оставить
        : borderColor as String?,   // передали (даже null) → применить
  );
}

copywith_property.code:
@override
AqElement copyWithProperty(String key, dynamic value) {
  return copyWith(
    id: key == 'id' ? value as String : null,
    borderColor: key == 'borderColor' ? value as String? : _absent,
  );
}

json_protocol.toJson_pattern:
Map<String, dynamic> toJson() => {
  'type': type,   // 'Column', 'Button' — PascalCase
  'id': id,
  'props': {
    if (padding != 16.0) 'padding': padding,
    if (borderColor != null) 'borderColor': borderColor,
  },
  if (base != AqBaseProps.defaults) 'base': base.toJson(),
  if (children.isNotEmpty) 'children': children.map((c) => c.toJson()).toList(),
  if (binding != null) 'binding': binding,
  if (action != null) 'action': action!.toJson(),
};

json_protocol.fromJson_pattern:
// top-level функция в aq_element.dart — поддержка v1 и v2
Map<String, dynamic> _readProps(Map<String, dynamic> json) {
  final v2 = json['props'] as Map<String, dynamic>?;
  if (v2 != null) return v2;
  return (json['properties'] as Map<String, dynamic>?) ?? {};
}

registry.initialization:
void main() async {
  WidgetsFlutterBinding.ensureInitialized();
  initializeAqElementRegistry();   // сначала модели
  registerAllComponentBuilders();  // потом билдеры
  runApp(...);
}
